          function getSliderConfig(slider) {
            const container = slider.closest('.custom-slider-container');
            if (!container) return { key: 'fpslimit', minFallback: 294, decimals: 0 };
            if (container.classList.contains('custom-slider-1')) return { key: 'spinSpeed', minFallback: 286, decimals: 0 };
            if (container.classList.contains('custom-slider-2')) return { key: 'fpslimit', minFallback: 294, decimals: 0 };
            if (container.classList.contains('custom-slider-3')) return { key: 'botSpeed', minFallback: 294, decimals: 2, summaryKey: 'botSpeed' };
            if (container.classList.contains('custom-slider-4')) return { key: 'botTargetDistance', minFallback: 294, decimals: 2, summaryKey: 'botTargetDistance' };
            if (container.classList.contains('custom-slider-5')) return { key: 'botPingPrediction', minFallback: 294, decimals: 2, summaryKey: 'botPingPrediction' };
            if (container.classList.contains('custom-slider-6')) return { key: 'visualsCount', minFallback: 294, decimals: 0, summaryKey: 'visualsCount' };
            if (container.classList.contains('custom-slider-7')) return { key: 'visualsSpeed', minFallback: 294, decimals: 2, summaryKey: 'visualsSpeed' };
            if (container.classList.contains('custom-slider-8')) return { key: 'visualsRadius', minFallback: 294, decimals: 2, summaryKey: 'visualsRadius' };
            if (container.classList.contains('custom-slider-9')) return { key: 'visualsSize', minFallback: 294, decimals: 2, summaryKey: 'visualsSize' };
            if (container.classList.contains('custom-slider-10')) return { key: 'predictionLineWidth', minFallback: 294, decimals: 1, summaryKey: 'predictionLineWidth' };
            return { key: 'fpslimit', minFallback: 294, decimals: 0 };
          }

          function formatSliderValue(value, decimals) {
            if (!decimals) return String(Math.round(value));
            return Number(value).toFixed(decimals).replace(/\.00$/, '').replace(/(\.\d)0$/, '$1');
          }

          function updateSliderVisuals(slider, options = {}) {
            const cfg = getSliderConfig(slider);
            const min = parseFloat(slider.dataset.min);
            const max = parseFloat(slider.dataset.max);
            let value = parseFloat(slider.dataset.value);
            value = Math.max(min, Math.min(max, value));
            value = cfg.decimals ? Number(value.toFixed(cfg.decimals)) : Math.round(value);
            slider.dataset.value = String(value);
            if (window.NovapackValues && cfg.key) {
              window.NovapackValues[cfg.key] = value;
            }
            const thumb = slider.querySelector('.slider-thumb');
            const trackFill = slider.querySelector('.slider-track-fill');
            const track = slider.querySelector('.slider-track');
            const formatted = formatSliderValue(value, cfg.decimals);
            if (thumb && thumb.textContent !== formatted) thumb.textContent = formatted;
            if (cfg.summaryKey) {
              const menuRoot = nvMenuRoot;
              const badgeSelector = `[data-bot-value="${cfg.summaryKey}"], [data-slider-value="${cfg.summaryKey}"]`;
              const badge = menuRoot && menuRoot.querySelector ? menuRoot.querySelector(badgeSelector) : null;
              if (badge) badge.textContent = formatted;
            }

            const percent = max === min ? 0 : (value - min) / (max - min);
            const measuredWidth = Math.max(
              slider.clientWidth || 0,
              Number(slider.dataset.measuredWidth || 0),
              track ? track.clientWidth || 0 : 0,
              options.forceMeasure ? Math.round(slider.getBoundingClientRect().width || 0) : 0,
              options.forceMeasure && track ? Math.round(track.getBoundingClientRect().width || 0) : 0
            );
            const thumbWidth = thumb ? Math.max(thumb.offsetWidth || 0, Number(slider.dataset.thumbWidth || 0), 44) : 44;

            if (!measuredWidth) {
              if (!options.skipRetry) {
                requestAnimationFrame(() => updateSliderVisuals(slider, { skipRetry: true, forceMeasure: true, persist: options.persist }));
              }
              syncBotSettingsToMY();
              if (options.persist) saveSettings();
              return;
            }

            const thumbPosition = Math.max(0, Math.min(measuredWidth - thumbWidth, percent * (measuredWidth - thumbWidth)));
            if (thumb) thumb.style.left = `${thumbPosition}px`;
            if (trackFill) trackFill.style.width = `${Math.max(thumbWidth / 2, thumbPosition + thumbWidth / 2)}px`;
            slider.dataset.measuredWidth = String(measuredWidth);
            slider.dataset.thumbWidth = String(thumbWidth);
            syncBotSettingsToMY();
            if (options.persist) saveSettings();
          }

          function refreshVisibleSliderVisuals(root = null) {
            const scope = root && typeof root.querySelectorAll === 'function' ? root : nvMenuRoot;
            const sliders = Array.from((scope && scope.querySelectorAll ? scope.querySelectorAll('.custom-slider') : []) || []);
            sliders.forEach(slider => {
              const rect = slider.getBoundingClientRect();
              if (rect.width > 0 && rect.height > 0) {
                updateSliderVisuals(slider, { skipRetry: true, forceMeasure: true, persist: false });
              }
            });
          }

          document.addEventListener('blur', (e) => {
            if (e.target && e.target.classList && e.target.classList.contains('bot-slider-value')) {
                const key = e.target.dataset.sliderValue || e.target.dataset.botValue;
                if (!key) return;
                let val = parseFloat(e.target.textContent);
                if (isNaN(val)) return;
                const container = e.target.closest('.control-item-vertical');
                if (container) {
                    const slider = container.querySelector('.custom-slider');
                    if (slider) {
                        slider.dataset.value = String(val);
                        updateSliderVisuals(slider, { persist: true, forceMeasure: true });
                    }
                }
            }
        }, true);
        document.addEventListener('keydown', (e) => {
            if (e.target && e.target.classList && e.target.classList.contains('bot-slider-value') && e.key === 'Enter') {
                e.preventDefault();
                e.target.blur();
            }
        });
        function setupSliderEvents(slider) {
            const thumb = slider.querySelector('.slider-thumb');
            let isDragging = false;

            const updateFromClientX = (clientX, persist = false) => {
              const rect = slider.getBoundingClientRect();
              if (rect.width === 0) return;
              const min = parseFloat(slider.dataset.min);
              const max = parseFloat(slider.dataset.max);
              let percent = (clientX - rect.left) / rect.width;
              percent = Math.max(0, Math.min(1, percent));
              slider.dataset.value = String(min + percent * (max - min));
              updateSliderVisuals(slider, { persist, forceMeasure: false });
            };

            thumb.addEventListener('mousedown', (e) => {
              isDragging = true;
              thumb.style.cursor = 'ew-resize';
              e.preventDefault();
            });

            slider.addEventListener('mousedown', (e) => {
              if (e.target === thumb) return;
              updateFromClientX(e.clientX, true);
            });

            window.addEventListener('mousemove', (e) => {
              if (!isDragging) return;
              updateFromClientX(e.clientX, false);
            });

            window.addEventListener('mouseup', () => {
              if (isDragging) {
                isDragging = false;
                thumb.style.cursor = 'pointer';
                updateSliderVisuals(slider, { persist: true, forceMeasure: false });
              }
            });

            thumb.addEventListener('keydown', (e) => {
              const allowed = ['Backspace', 'Delete', 'ArrowLeft', 'ArrowRight', 'Enter', 'Tab', '.', ','];
              if (!((e.key >= '0' && e.key <= '9') || allowed.includes(e.key))) {
                e.preventDefault();
              }
              if (e.key === 'Enter') {
                e.preventDefault();
                thumb.blur();
              }
            });

            thumb.addEventListener('blur', () => {
              let newValue = parseFloat(String(thumb.textContent).replace(',', '.'));
              if (isNaN(newValue)) newValue = parseFloat(slider.dataset.value);
              slider.dataset.value = String(newValue);
              updateSliderVisuals(slider, { persist: true, forceMeasure: true });
            });
          }

          function updateBgColor(color) {
            document.body.style.backgroundColor = color;
          }
          updateBgColor(window.NovapackValues.backgroundColor);


